package pl.msurvival.admin;import org.bukkit.*;import org.bukkit.command.*;import org.bukkit.entity.*;import org.bukkit.plugin.java.JavaPlugin;public final class MSurvivalAdmin extends JavaPlugin{public void onEnable(){saveDefaultConfig();}public boolean onCommand(CommandSender s,Command c,String l,String[] a){if(!s.hasPermission("msurvival.admin"))return true;Player p=s instanceof Player?(Player)s:null;String cmd=c.getName().toLowerCase();if(cmd.equals("fly")&&p!=null)p.setAllowFlight(!p.getAllowFlight());if(cmd.equals("gm")&&p!=null&&a.length>0)p.setGameMode(switch(a[0]){case"1"->GameMode.CREATIVE;case"2"->GameMode.ADVENTURE;case"3"->GameMode.SPECTATOR;default->GameMode.SURVIVAL;});if(cmd.equals("heal")&&p!=null)p.setHealth(p.getMaxHealth());if(cmd.equals("feed")&&p!=null){p.setFoodLevel(20);p.setSaturation(20);}if(cmd.equals("invsee")&&p!=null&&a.length>0){Player t=Bukkit.getPlayerExact(a[0]);if(t!=null)p.openInventory(t.getInventory());}if(cmd.equals("ecsee")&&p!=null&&a.length>0){Player t=Bukkit.getPlayerExact(a[0]);if(t!=null)p.openInventory(t.getEnderChest());}return true;}}
